package main

import (
	"bytes"
	"fmt"
	"math/rand/v2"
	"os"
	"os/exec"
	"path/filepath"
	"strings"

	fiatshamir "github.com/consensys/linea-monorepo/prover-ray/crypto/koalabear/fiatshamir"
	poseidon2 "github.com/consensys/linea-monorepo/prover-ray/crypto/koalabear/poseidon2"
	"github.com/consensys/linea-monorepo/prover-ray/maths/koalabear/field"
	"github.com/consensys/linea-monorepo/prover-ray/maths/koalabear/polynomials"
)

const koalaModulus = uint64(2_130_706_433)

func main() {
	var out bytes.Buffer
	writeHeader(&out)
	writeFieldCases(&out)
	writeExtCases(&out)
	writePolynomialCases(&out)
	writePoseidonCases(&out)
	writeFiatShamirCases(&out)

	data := out.Bytes()
	zigfmt, err := runZigFmt(data)
	if err == nil {
		data = zigfmt
	}

	outputPath := filepath.Join("..", "generated", "vectors.zig")
	if err := os.WriteFile(outputPath, data, 0o644); err != nil {
		panic(err)
	}
}

func writeHeader(out *bytes.Buffer) {
	fmt.Fprintln(out, "// Code generated by verifier-ray/testdata/generate; DO NOT EDIT.")
	fmt.Fprintln(out)
	fmt.Fprintln(out, "pub const FieldCase = struct {")
	fmt.Fprintln(out, "    a: u32,")
	fmt.Fprintln(out, "    b: u32,")
	fmt.Fprintln(out, "    add: u32,")
	fmt.Fprintln(out, "    sub: u32,")
	fmt.Fprintln(out, "    mul: u32,")
	fmt.Fprintln(out, "    square_a: u32,")
	fmt.Fprintln(out, "    neg_a: u32,")
	fmt.Fprintln(out, "    has_inv_a: bool,")
	fmt.Fprintln(out, "    inv_a: u32,")
	fmt.Fprintln(out, "    has_div_ab: bool,")
	fmt.Fprintln(out, "    div_ab: u32,")
	fmt.Fprintln(out, "    bytes_a: [4]u8,")
	fmt.Fprintln(out, "};")
	fmt.Fprintln(out)
	fmt.Fprintln(out, "pub const ExtCase = struct {")
	fmt.Fprintln(out, "    a: [6]u32,")
	fmt.Fprintln(out, "    b: [6]u32,")
	fmt.Fprintln(out, "    scalar: u32,")
	fmt.Fprintln(out, "    add: [6]u32,")
	fmt.Fprintln(out, "    sub: [6]u32,")
	fmt.Fprintln(out, "    mul: [6]u32,")
	fmt.Fprintln(out, "    square_a: [6]u32,")
	fmt.Fprintln(out, "    neg_a: [6]u32,")
	fmt.Fprintln(out, "    mul_by_base: [6]u32,")
	fmt.Fprintln(out, "    has_inv_a: bool,")
	fmt.Fprintln(out, "    inv_a: [6]u32,")
	fmt.Fprintln(out, "    bytes_a: [24]u8,")
	fmt.Fprintln(out, "};")
	fmt.Fprintln(out)
	fmt.Fprintln(out, "pub const CanonicalBaseCase = struct { coeffs: []const u32, point: u32, expected: u32 };")
	fmt.Fprintln(out, "pub const CanonicalBaseAtExtCase = struct { coeffs: []const u32, point: [6]u32, expected: [6]u32 };")
	fmt.Fprintln(out, "pub const CanonicalExtAtBaseCase = struct { coeffs: []const [6]u32, point: u32, expected: [6]u32 };")
	fmt.Fprintln(out, "pub const CanonicalExtCase = struct { coeffs: []const [6]u32, point: [6]u32, expected: [6]u32 };")
	fmt.Fprintln(out, "pub const LagrangeBaseCase = CanonicalBaseCase;")
	fmt.Fprintln(out, "pub const LagrangeBaseAtExtCase = CanonicalBaseAtExtCase;")
	fmt.Fprintln(out, "pub const LagrangeExtAtBaseCase = CanonicalExtAtBaseCase;")
	fmt.Fprintln(out, "pub const LagrangeExtCase = CanonicalExtCase;")
	fmt.Fprintln(out)
	fmt.Fprintln(out, "pub const PoseidonCompressCase = struct { left: [8]u32, right: [8]u32, expected: [8]u32 };")
	fmt.Fprintln(out, "pub const PoseidonMdCase = struct { message: []const u32, expected: [8]u32 };")
	fmt.Fprintln(out, "pub const FiatShamirCase = struct { base_updates: []const u32, ext_updates: []const [6]u32, random_field: [8]u32, random_ext: [6]u32 };")
	fmt.Fprintln(out)
}

func writeFieldCases(out *bytes.Buffer) {
	rng := rand.New(rand.NewPCG(0x12345678, 0x9abcdef0))
	values := []field.Element{
		elem(0),
		elem(1),
		elem(2),
		elem(3),
		elem(koalaModulus - 1),
		elem(koalaModulus - 2),
		elem(uint64(field.RootOfUnity.Bits()[0])),
		elem(uint64(field.MontConstant.Bits()[0])),
	}
	for range 8 {
		values = append(values, field.PseudoRand(rng))
	}

	fmt.Fprintln(out, "pub const field_cases = [_]FieldCase{")
	for i := 0; i < len(values)-1; i++ {
		writeFieldCase(out, values[i], values[i+1])
	}
	fmt.Fprintln(out, "};")
	fmt.Fprintln(out)
}

func writeFieldCase(out *bytes.Buffer, a, b field.Element) {
	var add, sub, mul, square, neg, inv, div field.Element
	add.Add(&a, &b)
	sub.Sub(&a, &b)
	mul.Mul(&a, &b)
	square.Square(&a)
	neg.Neg(&a)

	hasInv := !a.IsZero()
	if hasInv {
		inv.Inverse(&a)
	}
	hasDiv := !b.IsZero()
	if hasDiv {
		div.Div(&a, &b)
	}

	fmt.Fprintf(out, "    .{ .a = %d, .b = %d, .add = %d, .sub = %d, .mul = %d, .square_a = %d, .neg_a = %d, .has_inv_a = %t, .inv_a = %d, .has_div_ab = %t, .div_ab = %d, .bytes_a = %s },\n",
		u(a), u(b), u(add), u(sub), u(mul), u(square), u(neg), hasInv, u(inv), hasDiv, u(div), bytes4(a.Bytes()))
}

func writeExtCases(out *bytes.Buffer) {
	rng := rand.New(rand.NewPCG(0x11111111, 0x22222222))
	values := []field.Ext{
		field.UintsToExt(0, 0, 0, 0, 0, 0),
		field.UintsToExt(1, 0, 0, 0, 0, 0),
		field.UintsToExt(0, 1, 0, 0, 0, 0),
		field.UintsToExt(0, 0, 1, 0, 0, 0),
		field.UintsToExt(0, 0, 0, 1, 0, 0),
		field.UintsToExt(0, 0, 0, 0, 1, 0),
		field.UintsToExt(0, 0, 0, 0, 0, 1),
		field.UintsToExt(1, 2, 3, 4, 5, 6),
		field.UintsToExt(koalaModulus-1, koalaModulus-2, 7, 11, 13, 17),
	}
	for range 6 {
		values = append(values, field.PseudoRandExt(rng))
	}

	scalars := []field.Element{elem(0), elem(1), elem(2), elem(17), elem(koalaModulus - 1)}

	fmt.Fprintln(out, "pub const ext_cases = [_]ExtCase{")
	for i := 0; i < len(values)-1; i++ {
		writeExtCase(out, values[i], values[i+1], scalars[i%len(scalars)])
	}
	fmt.Fprintln(out, "};")
	fmt.Fprintln(out)
}

func writeExtCase(out *bytes.Buffer, a, b field.Ext, scalar field.Element) {
	var add, sub, mul, square, neg, byBase, inv field.Ext
	add.Add(&a, &b)
	sub.Sub(&a, &b)
	mul.Mul(&a, &b)
	square.Square(&a)
	neg.Neg(&a)
	byBase.MulByElement(&a, &scalar)

	hasInv := !a.IsZero()
	if hasInv {
		inv.Inverse(&a)
	}

	bytesA := field.ExtToBytes(&a)
	fmt.Fprintf(out, "    .{ .a = %s, .b = %s, .scalar = %d, .add = %s, .sub = %s, .mul = %s, .square_a = %s, .neg_a = %s, .mul_by_base = %s, .has_inv_a = %t, .inv_a = %s, .bytes_a = %s },\n",
		ext6(a), ext6(b), u(scalar), ext6(add), ext6(sub), ext6(mul), ext6(square), ext6(neg), ext6(byBase), hasInv, ext6(inv), bytes24(bytesA))
}

func writePolynomialCases(out *bytes.Buffer) {
	basePolyA := []field.Element{elem(0), elem(1), elem(koalaModulus - 1), elem(17), elem(123456)}
	basePolyB := []field.Element{elem(9), elem(8), elem(7), elem(6)}
	extPolyA := []field.Ext{
		field.UintsToExt(1, 2, 3, 4, 5, 6),
		field.UintsToExt(0, 1, 0, 1, 2, 3),
		field.UintsToExt(9, 0, 8, 0, 4, 5),
		field.UintsToExt(11, 12, 13, 14, 6, 7),
	}
	extPolyB := []field.Ext{
		field.UintsToExt(4, 3, 2, 1, 5, 6),
		field.UintsToExt(5, 0, 0, 6, 7, 8),
		field.UintsToExt(7, 8, 9, 10, 11, 12),
	}

	basePoint := elem(5)
	basePoint2 := elem(19)
	extPoint := field.UintsToExt(5, 1, 7, 2, 3, 4)
	extPoint2 := field.UintsToExt(13, 3, 0, 4, 5, 6)

	fmt.Fprintln(out, "pub const canonical_base_cases = [_]CanonicalBaseCase{")
	writeCanonicalBaseCase(out, basePolyA, basePoint)
	writeCanonicalBaseCase(out, basePolyB, basePoint2)
	fmt.Fprintln(out, "};")
	fmt.Fprintln(out)

	fmt.Fprintln(out, "pub const canonical_base_at_ext_cases = [_]CanonicalBaseAtExtCase{")
	writeCanonicalBaseAtExtCase(out, basePolyA, extPoint)
	writeCanonicalBaseAtExtCase(out, basePolyB, extPoint2)
	fmt.Fprintln(out, "};")
	fmt.Fprintln(out)

	fmt.Fprintln(out, "pub const canonical_ext_at_base_cases = [_]CanonicalExtAtBaseCase{")
	writeCanonicalExtAtBaseCase(out, extPolyA, basePoint)
	writeCanonicalExtAtBaseCase(out, extPolyB, basePoint2)
	fmt.Fprintln(out, "};")
	fmt.Fprintln(out)

	fmt.Fprintln(out, "pub const canonical_ext_cases = [_]CanonicalExtCase{")
	writeCanonicalExtCase(out, extPolyA, extPoint)
	writeCanonicalExtCase(out, extPolyB, extPoint2)
	fmt.Fprintln(out, "};")
	fmt.Fprintln(out)

	lagrangeBase := []field.Element{elem(3), elem(1), elem(4), elem(1)}
	lagrangeExt := []field.Ext{
		field.UintsToExt(3, 1, 4, 1, 5, 9),
		field.UintsToExt(5, 9, 2, 6, 5, 3),
		field.UintsToExt(5, 3, 5, 8, 9, 7),
		field.UintsToExt(9, 7, 9, 3, 2, 3),
	}
	lagrangeBasePoint := elem(7)
	lagrangeExtPoint := field.UintsToExt(7, 2, 0, 1, 4, 5)

	fmt.Fprintln(out, "pub const lagrange_base_cases = [_]LagrangeBaseCase{")
	writeLagrangeBaseCase(out, lagrangeBase, lagrangeBasePoint)
	fmt.Fprintln(out, "};")
	fmt.Fprintln(out)

	fmt.Fprintln(out, "pub const lagrange_base_at_ext_cases = [_]LagrangeBaseAtExtCase{")
	writeLagrangeBaseAtExtCase(out, lagrangeBase, lagrangeExtPoint)
	fmt.Fprintln(out, "};")
	fmt.Fprintln(out)

	fmt.Fprintln(out, "pub const lagrange_ext_at_base_cases = [_]LagrangeExtAtBaseCase{")
	writeLagrangeExtAtBaseCase(out, lagrangeExt, lagrangeBasePoint)
	fmt.Fprintln(out, "};")
	fmt.Fprintln(out)

	fmt.Fprintln(out, "pub const lagrange_ext_cases = [_]LagrangeExtCase{")
	writeLagrangeExtCase(out, lagrangeExt, lagrangeExtPoint)
	fmt.Fprintln(out, "};")
	fmt.Fprintln(out)
}

func writeCanonicalBaseCase(out *bytes.Buffer, coeffs []field.Element, point field.Element) {
	res := polynomials.EvalCanonical(field.VecFromBase(coeffs), field.ElemFromBase(point))
	fmt.Fprintf(out, "    .{ .coeffs = &%s, .point = %d, .expected = %d },\n", elemSlice(coeffs), u(point), u(res.AsBase()))
}

